text:
Create model list and fit
I this section of code we construct a list for all desired encounters and groups size model specifications. We then fit all the models and produce a table of models and AIC values.

Encounter rate models
Specification of the encounter rate model set is somewhat tricky due to the fact there are are several restrictions on the set of all possible models, namely due to the inclusion of Latitude interaction effects. The encounter rate models included all combinations of the 4 oceanographic variables: sst, ssh, mld, and salinity (including none) along with all combinations of the focal standard deviation versions: sst_sd, ssh_sd, mld_sd, and salinity_sd. The _sd versions are meant to examine the effect of fronts within the gradients of these variables. In addition to this model set we also added an interaction term of the form te(var,Latitude) for interaction effects of Latitude on the main variables. Only 1 main variable was allowed to interact with Latitude at a time. The reulting list is comprised of 767 models.

hab_var &lt;- c("sst","ssh","mld","salinity")
hab_var_sd &lt;- c("sst_sd","ssh_sd","mld_sd","salinity_sd")

hab_inc &lt;- expand.grid(rep(list(0:2), length(hab_var)))
hab_inc &lt;- hab_inc[apply(hab_inc==2, 1, sum)&lt;2,]
hab_sd_inc &lt;- expand.grid(rep(list(0:1), length(hab_var_sd)))

form_hab &lt;- apply(hab_inc, 1, function(row) {
  terms &lt;- mapply(function(choice, var) {
    if (choice == 1) return(paste0("s(",var,",bs=spline2use,k=5)"))
    if (choice == 2) return(paste0("te(", var, ",Latitude,bs=spline2use,k=5)"))
    return(NULL)
  }, row, hab_var)
  terms &lt;- unlist(terms)
  if (length(terms) == 0) return("nSI_033 ~ ")  # skip null model
  paste("nSI_033 ~", paste(terms, collapse = " + "))
}) %&gt;% unlist()

form_hab_sd &lt;- apply(hab_sd_inc, 1, function(row) {
  terms &lt;- mapply(function(choice, var) {
    if (choice == 1) return(paste0("s(",var,",bs=spline2use,k=5)"))
    return(NULL)
  }, row, hab_var_sd)
  terms &lt;- unlist(terms)
  # if (length(terms) == 0) return(NULL)  # skip null model
  paste(terms, collapse = " + ")
}) %&gt;% unlist()

forms_er &lt;- NULL
for(i in seq_along(form_hab)){
  if(i ==1) {
    tmp &lt;- paste(form_hab[i], form_hab_sd[-1], sep="")
  } else {
    tmp &lt;- c(form_hab[i], paste(form_hab[i], form_hab_sd[-1], sep=" + "))
  }
  forms_er &lt;- c(forms_er, tmp)
}



Fit all ER models
In this section we fit all 767 encounter rate models to determine the AIC optimal model as well as the relative rankings of different models, etc.
Warning!!! This takes a while to implement so it was partitioned and chunks of models were fit in parallel.

#' Select spline type
#' 'ts'= thin plate splines ("shrinkage approach" applies additional smoothing penalty)
#' "tp" is default for s()
spline2use &lt;- "ts" 

workers &lt;- 8
plan("multisession", workers=workers)
# forms &lt;- split(forms, cut(seq_along(forms), breaks = workers, labels = FALSE))

with_progress({
  pb &lt;- progressor(along = forms_er) 
  ergam_list &lt;- foreach(
    i = seq_along(forms_er), .options.future = list(seed = TRUE), 
    .errorhandling = "pass") %dofuture% {
      spline2use &lt;- spline2use
      gam_fit &lt;- gam(formula = as.formula(forms_er[i]), offset = log(effort),
                     family = tw(),
                     method="REML", 
                     data = fkw_dsm_data, weights = ProbPel)
      pb()
      list(summary = summary(gam_fit), aic=gam_fit$aic)
    }
})
plan("sequential")

mod_df &lt;- data.frame(
  idx = 1:length(ergam_list),
  form = forms_er, 
  aic = sapply(ergam_list, \(x) x$aic), 
  dev_expl=sapply(ergam_list, \(x) x$summary$dev.expl*100)
) %&gt;% mutate(
  waic = exp(-0.5*(aic-min(aic))),
  waic = waic/sum(waic)
) %&gt;% arrange(desc(waic))



Group size model
The group size model set is relatively easy to for as it simply consists of every combination of the 4 oceanographic variables for a total of 16 models.

hab_inc_gs &lt;- expand.grid(rep(list(0:1), length(hab_var)))
forms_gs &lt;- apply(hab_inc_gs, 1, function(row) {
  terms &lt;- mapply(function(choice, var) {
    if (choice == 1) return(paste0("s(",var,",bs=spline2use,k=5)"))
    return(NULL)
  }, row, hab_var)
  terms &lt;- unlist(terms)
  # if (length(terms) == 0) return(NULL)  # skip null model
  paste(terms, collapse = " + ")
}) %&gt;% unlist()
forms_gs &lt;- paste("log(ANI_033)", forms_gs, sep=" ~ ")
forms_gs[1] &lt;- "log(ANI_033) ~ 1"



Fit all GS models

gsgam_list &lt;- foreach(
  i = seq_along(forms_gs), .options.future = list(seed = TRUE), 
  .errorhandling = "pass") %do% {
    spline2use &lt;- spline2use
    gam_fit &lt;- gam(formula = as.formula(forms_gs[i]),
                   method="REML", 
                   data = fkw_gs, weights = ProbPel)
    list(summary = summary(gam_fit), aic=gam_fit$aic)
  }

mod_df_gs &lt;- data.frame(
  idx = 1:length(gsgam_list),
  form = forms_gs, 
  aic = sapply(gsgam_list, \(x) x$aic), 
  dev_expl=sapply(gsgam_list, \(x) x$summary$dev.expl*100)
) %&gt;% mutate(
  waic = exp(-0.5*(aic-min(aic))),
  waic = waic/sum(waic)
) %&gt;% arrange(desc(waic))

pred_avg &lt;- vector("list",length(years))

for(i in seq_along(years)){
  tifs &lt;- N_data$file[N_data$year==years[i]]
  pred &lt;- rast(file.path(local_wd, "output","predictions",tifs[1]))
  for(j in 2:length(tifs)){
    pred &lt;- c(pred, rast(file.path(local_wd, "output","predictions",tifs[j])))
  }
  pred_avg[[i]] &lt;- mean(pred)
}
pred_avg &lt;- do.call(c, pred_avg)
names(pred_avg) &lt;- years

writeRaster(pred_avg, file.path(local_wd,"output","yearly_avg_abund.tif"), overwrite=TRUE)

Save processed segment data

if (!dir.exists(file.path(localwd,"output"))) {
  dir.create(file.path(localwd,"output"))
}

saveRDS(y.eff.sight.strata, file.path(localwd,"output", "seg_sight_out.rds"))
